import{_ as d,o as a,c as e,a2 as r}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"安装路线","description":"","frontmatter":{},"headers":[],"relativePath":"guide/start.md","filePath":"guide/start.md","lastUpdated":1783966097000}'),l={name:"guide/start.md"};function i(o,t,h,s,c,n){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="安装路线" tabindex="-1">安装路线 <a class="header-anchor" href="#安装路线" aria-label="Permalink to &quot;安装路线&quot;">​</a></h1><p>本页按推荐安装顺序整理。建议先跑通最小闭环，再逐步增加插件和复杂配置。</p><h2 id="第一步-准备服务端" tabindex="-1">第一步：准备服务端 <a class="header-anchor" href="#第一步-准备服务端" aria-label="Permalink to &quot;第一步：准备服务端&quot;">​</a></h2><p>推荐使用 Paper 或 Purpur。<br> 版本根据插件目标选择，GT 系列会尽量覆盖常见版本，但低版本服端需要额外注意 Java 和依赖兼容。</p><p>建议先确认：</p><ul><li>服务端可以正常启动。</li><li><code>plugins</code> 文件夹存在。</li><li>控制台没有其他插件刷屏报错。</li><li>服务器能访问外网，用于下载依赖或验证。</li></ul><h2 id="第二步-安装基础依赖" tabindex="-1">第二步：安装基础依赖 <a class="header-anchor" href="#第二步-安装基础依赖" aria-label="Permalink to &quot;第二步：安装基础依赖&quot;">​</a></h2><p>不同插件需要的依赖不完全一样，下面是常见组合：</p><table tabindex="0"><thead><tr><th>依赖</th><th>用途</th><th>建议</th></tr></thead><tbody><tr><td>PlaceholderAPI</td><td>变量、条件、显示文本</td><td>推荐安装</td></tr><tr><td>Vault</td><td>经济接口</td><td>需要金币消耗时安装</td></tr><tr><td>ProtocolLib</td><td>发包、显示、兼容</td><td>使用显示类功能时推荐安装</td></tr><tr><td>PacketEvents</td><td>高版本发包能力</td><td>需要时安装</td></tr><tr><td>MythicMobs</td><td>怪物、技能、MM 物品</td><td>做 RPG 基本必装</td></tr><tr><td>NeigeItems / ItemsAdder / Oraxen / CraftEngine</td><td>物品库</td><td>按服务器实际选择</td></tr><tr><td>AttributePlus / CraneAttribute / SX-Attribute</td><td>属性来源</td><td>按服务器实际选择</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">控制首次测试范围</p><p>物品库和属性插件可以兼容多个。首次测试建议只保留当前玩法实际需要的插件，先跑通一条链路，再补更多兼容。</p></div><h2 id="第三步-安装-gtcore" tabindex="-1">第三步：安装 GTCore <a class="header-anchor" href="#第三步-安装-gtcore" aria-label="Permalink to &quot;第三步：安装 GTCore&quot;">​</a></h2><ol><li>将 <code>GTCore.jar</code> 放入 <code>plugins</code>。</li><li>启动服务器一次。</li><li>确认生成 <code>plugins/GTCore/</code> 文件夹。</li><li>关闭服务器。</li><li>打开 <code>plugins/GTCore/config.yml</code>，填写 QQ 和插件激活码。</li><li>重新启动服务器。</li></ol><p>启动成功后，控制台应能看到 GTCore 启动信息。</p><h2 id="第四步-安装业务插件" tabindex="-1">第四步：安装业务插件 <a class="header-anchor" href="#第四步-安装业务插件" aria-label="Permalink to &quot;第四步：安装业务插件&quot;">​</a></h2><p>根据你要的玩法安装：</p><table tabindex="0"><thead><tr><th>玩法</th><th>插件</th></tr></thead><tbody><tr><td>免费测试怪物掉落</td><td>GTMobDropsLite</td></tr><tr><td>完整怪物掉落</td><td>GTMobDrops</td></tr><tr><td>宝石镶嵌</td><td>GTGem</td></tr><tr><td>采集点</td><td>GTGather</td></tr><tr><td>CDK / 兑换</td><td>GTCDK</td></tr><tr><td>伤害数字 / 怪物血条</td><td>GTDamage</td></tr><tr><td>箭袋 / 自定义箭</td><td>GTQuiver</td></tr></tbody></table><p>安装方式：</p><ol><li>将插件放入 <code>plugins</code>。</li><li>启动服务器生成配置。</li><li>关闭服务器。</li><li>修改配置。</li><li>重新启动服务器测试。</li></ol><h2 id="第五步-跑最小闭环" tabindex="-1">第五步：跑最小闭环 <a class="header-anchor" href="#第五步-跑最小闭环" aria-label="Permalink to &quot;第五步：跑最小闭环&quot;">​</a></h2><p>先让每个插件完成一个最小动作，再继续添加复杂配置。</p><table tabindex="0"><thead><tr><th>插件</th><th>最小测试</th></tr></thead><tbody><tr><td>GTMobDrops</td><td>一个 MM 怪物掉落一个原版物品</td></tr><tr><td>GTMobDropsLite</td><td>一个 MM 怪物配置 <code>GTDrops</code></td></tr><tr><td>GTGem</td><td>一个宝石能镶嵌到一件装备</td></tr><tr><td>GTGather</td><td>一个采集点采集后给一个物品</td></tr><tr><td>GTCDK</td><td>一个 CDK 能兑换一次奖励</td></tr><tr><td>GTDamage</td><td>打怪时能显示伤害数字或血条</td></tr><tr><td>GTQuiver</td><td>背包无箭时用装备箭袋中的普通箭完成一次射击</td></tr></tbody></table><h2 id="检查点" tabindex="-1">检查点 <a class="header-anchor" href="#检查点" aria-label="Permalink to &quot;检查点&quot;">​</a></h2><p>安装完成后，用这个表检查：</p><ul><li>控制台没有红色报错。</li><li><code>/plugins</code> 能看到插件是绿色启用状态。</li><li>GTCore 已经先于业务插件启动。</li><li>物品库、属性插件、MythicMobs 已经安装。</li><li>PlaceholderAPI 变量能正常解析。</li><li>修改 YAML 后没有缩进错误。</li></ul><h2 id="常见错误" tabindex="-1">常见错误 <a class="header-anchor" href="#常见错误" aria-label="Permalink to &quot;常见错误&quot;">​</a></h2><h3 id="插件没有生成配置" tabindex="-1">插件没有生成配置 <a class="header-anchor" href="#插件没有生成配置" aria-label="Permalink to &quot;插件没有生成配置&quot;">​</a></h3><p>通常是插件没有成功启用。排查时从控制台最早的报错开始看。</p><h3 id="配置改了没生效" tabindex="-1">配置改了没生效 <a class="header-anchor" href="#配置改了没生效" aria-label="Permalink to &quot;配置改了没生效&quot;">​</a></h3><p>优先完整重启服务器。很多玩法涉及缓存、脚本、物品库和属性读取，热重载不一定能完全刷新。</p><h3 id="物品识别不到" tabindex="-1">物品识别不到 <a class="header-anchor" href="#物品识别不到" aria-label="Permalink to &quot;物品识别不到&quot;">​</a></h3><p>先确认对应物品库插件已经启用，再确认物品 ID 写法和文档一致。</p>',31)])])}const b=d(l,[["render",i]]);export{u as __pageData,b as default};
